// Shared across all tabs
const worker = new SharedWorker('sync.js');

worker.port.postMessage({
  type: 'update',
  cart: cartItems
});

worker.port.onmessage = (e) =&gt; {
  // All tabs get the same state
  updateUI(e.data);
};

// sync.js
const ports = [];
self.onconnect = (e) =&gt; {
  const port = e.ports[0];
  ports.push(port);
  port.onmessage = (msg) =&gt; {
    ports.forEach(p =&gt; p.postMessage(msg.data));
  };
};

// Without transfer — COPIES the data
worker.postMessage(buffer);
// buffer is still usable here (but slow)

// With transfer — MOVES the data
worker.postMessage(buffer, [buffer]);
// buffer is now EMPTY here (but instant)

